                         goto fatal;
                 break;
         case 0x89:
-                if (str_join(&err, &ctx->container_flags, "no-cntlibs", " ") < 0)
+                /* The --no-cntlibs command line flag is equivalent to --cuda-compat-mode=disabled. */
+                if (str_join(&err, &ctx->container_flags, "cuda-compat-mode=disabled", " ") < 0)
+                        goto fatal;
