                         goto fatal;
                 break;
         case ARGP_KEY_ARG:
@@ -316,6 +326,15 @@ configure_command(const struct context *ctx)
                 goto fail;
         }

+        /*
+         * We now have the driver version and can update the list of compat
+         * libraries discovered above accordingly.
