                 $(SRCS_DIR)/dxcore.c        \
                 $(SRCS_DIR)/elftool.c       \
                 $(SRCS_DIR)/error_generic.c \
@@ -73,7 +72,10 @@ LIB_SRCS     := $(SRCS_DIR)/cgroup_legacy.c \
                 $(SRCS_DIR)/utils.c

 ifeq ($(WITH_NVCGO), yes)
