+            checkout scm
+        }
+        stage('dependencies') {
+            container('docker') {
+                sh 'apk add --no-cache make bash'
+            }
+        }
+        stage('build-one') {
+            parallel (
+                getSingleBuildForArchitectures(["amd64", "ppc64le", "arm64"])
+            )
+        }
+        stage('build-all') {
+            parallel (
+                getAllBuildForArchitectures(["amd64", "ppc64le", "arm64", "x86_64", "aarch64"])
+            )
+        }
+    }
+}
